import { BrowserRouter,BrowserRouter as Route, Router, Routes} from "react-router-dom";
import { useState } from "react";
import Auth from "./Auth";


const Login = () => {
  const REST_API_KEY = "32bb1444ddc8c71c3924daaef84ae5e6";
  const REDIRECT_URI = "http://localhost:3007/oauth/kakao/callback";
  const KAKAO_AUTH_URL = `https://kauth.kakao.com/oauth/authorize?client_id=${REST_API_KEY}&redirect_uri=${REDIRECT_URI}&response_type=code`;


  const [flavor, setflavor] = useState();
    const handleClickRadioButton1 = (e) =>{
      console.log(e.target.value);
      setflavor(e.target.value)
    }

    const [spicy, setspicy] = useState();
    const handleClickRadioButton2 = (e) =>{
      console.log(e.target.value);
      setspicy(e.target.value)
    }

    const [meat, setmeat] = useState();
    const handleClickRadioButton3 = (e) =>{
      console.log(e.target.value);
      setmeat(e.target.value)
    }
  return (
   <div>
    <div className = "kakao">
        <a href={KAKAO_AUTH_URL}>Kakao Login</a>
    </div>

    <div className="marr_type">
      <h2>나의 마라 취향</h2>
      <div className = "type">
      <h3>향신료  <img src={flavor_img}  style={{ width: '3%'}} /> </h3>

        <label>
        <input
            type="radio"
            value = "1"
            checked = {flavor==="1"}
            onChange = {handleClickRadioButton1}
          />
            상
          </label>
          <label>
          <input
            type="radio"
            value = "2"
            checked = {flavor==="2"}
            onChange = {handleClickRadioButton1}
          />
            중
          </label>
          <label>
          <input
            type="radio"
            value = "3"
            checked = {flavor==="3"}
            onChange = {handleClickRadioButton1}
          />
            하
          </label>


        <h3>맵기  <img src={spicy_img}  style={{ width: '3%'}} /></h3>
        <label>
        <input
            type="radio"
            value = "1"
            checked = {spicy==="1"}
            onChange = {handleClickRadioButton2}
          />
            상
          </label>
          <label>
          <input
            type="radio"
            value = "2"
            checked = {spicy==="2"}
            onChange = {handleClickRadioButton2}
          />
            중
          </label>
          <label>
          <input
            type="radio"
            value = "3"
            checked = {spicy==="3"}
            onChange = {handleClickRadioButton2}
          />
            하
          </label>

        <h3>고기종류  <img src={meat_img}  style={{ width: '3%'}} /></h3>
          <label>
          <input
              type="radio"
              value = "1"
              checked = {meat==="1"}
              onChange = {handleClickRadioButton3}
            />
              양고기
            </label>
            <label>
            <input
              type="radio"
              value = "2"
              checked = {meat==="2"}
              onChange = {handleClickRadioButton3}
            />
              소고기
            </label>
            <label>
            <input
              type="radio"
              value = "3"
              checked = {meat==="3"}
              onChange = {handleClickRadioButton3}
            />
              둘다
            </label>

      </div>
    </div>

   </div>

  );
}
export default Login;
